#include<cstdio>
using namespace std;

int main()
{
	int n,a[1001],s=0,i,j;
	scanf("%d",&n);
	if(n==1)
	{
		printf("1");
		return 0;
	}
	printf("1 ");
	a[1]=n;
	for(i=2; ;i++)
	{
		if(n%2==0)
		{
			n=n/2;
		    a[i]=n;	
			s++;
	    }
	    else
	    {
		    n=n*3+1;
			a[i]=n;
			s++;
		}
		if(a[i]==1)
		{
			break;
		}

	}
	for(j=s;j>=1;j--)
	{
		printf("%d ",a[j]);
	}
	return 0;
}
